import os
import re

nogao_dir = r'C:\Users\lx\Desktop\前期准备\诺皋'

# Read original text
with open(os.path.join(nogao_dir, '酉阳杂俎诺皋.txt'), 'r', encoding='utf-8') as f:
    content = f.read()

# Split into paragraphs by blank lines
paragraphs = [p.strip() for p in content.split('\n\n') if p.strip()]

# Filter out non-story paragraphs and duplicates
titles = {'诺皋记上', '诺皋记下', '支诺皋上', '支诺皋中', '支诺皋下'}
seen = set()
story_paragraphs = []

for p in paragraphs:
    # Skip section titles
    if p in titles:
        continue
    # Skip single-line encyclopedia entries or folk sayings
    if len(p) < 80 and ('相传' in p[:10] or '或云' in p or '世有' in p[:2]):
        continue
    # Skip duplicate (line 26 and 28 are duplicates in original)
    first_line = p.split('\n')[0].strip()
    if first_line in seen:
        continue
    # Skip the duplicate specific one
    if '天宝初，安思顺进五色玉带' in p and '又于左藏库中得五色玉杯。上怪近日西尽无五色玉，令责安西诸蕃。蕃言：“比常进皆为小勃律所劫，不达。”' in p:
        # This is the duplicate with different quotes, skip if already seen similar
        normalized = re.sub(r'[「""]', '', p[:100])
        if normalized in seen:
            continue
        seen.add(normalized)
        story_paragraphs.append(p)
        continue
    seen.add(first_line)
    story_paragraphs.append(p)

# Special handling: remove the pure duplicate at line 28
# We will deduplicate by checking if two paragraphs start with same first sentence
deduped = []
for p in story_paragraphs:
    fl = p.split('。')[0] + '。'
    if not any((q.split('。')[0] + '。') == fl for q in deduped):
        deduped.append(p)

story_paragraphs = deduped

